"use client";

import { motion, useMotionValue, useSpring, useTransform } from "motion/react";
import { useEffect, useRef, useState } from "react";

const SPRING_CONFIG = { stiffness: 300, damping: 30, mass: 0.5 };
const DOT_SPACING = 28;
const DOT_SIZE = 2;
const REPULSION_RADIUS = 90;
const REPULSION_STRENGTH = 22;

interface Dot {
  id: string;
  baseX: number;
  baseY: number;
  opacity: number;
}

function generateDots(width: number, height: number): Dot[] {
  const dots: Dot[] = [];
  const cols = Math.ceil(width / DOT_SPACING);
  const rows = Math.ceil(height / DOT_SPACING);
  for (let row = 0; row <= rows; row++) {
    for (let col = 0; col <= cols; col++) {
      const pattern = (row + col) % 3;
      const baseOpacities = [0.07, 0.12, 0.18];
      dots.push({
        id: `d-${row}-${col}`,
        baseX: col * DOT_SPACING,
        baseY: row * DOT_SPACING,
        opacity: baseOpacities[pattern],
      });
    }
  }
  return dots;
}

function DotItem({
  dot,
  index,
  mouseX,
  mouseY,
}: {
  dot: Dot;
  index: number;
  mouseX: ReturnType<typeof useMotionValue<number>>;
  mouseY: ReturnType<typeof useMotionValue<number>>;
}) {
  const posX = useTransform([mouseX, mouseY], () => {
    const mx = mouseX.get(), my = mouseY.get();
    if (!Number.isFinite(mx) || !Number.isFinite(my)) return 0;
    const dx = dot.baseX - mx, dy = dot.baseY - my;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist < REPULSION_RADIUS) {
      const force = (1 - dist / REPULSION_RADIUS) * REPULSION_STRENGTH;
      return Math.cos(Math.atan2(dy, dx)) * force;
    }
    return 0;
  });

  const posY = useTransform([mouseX, mouseY], () => {
    const mx = mouseX.get(), my = mouseY.get();
    if (!Number.isFinite(mx) || !Number.isFinite(my)) return 0;
    const dx = dot.baseX - mx, dy = dot.baseY - my;
    const dist = Math.sqrt(dx * dx + dy * dy);
    if (dist < REPULSION_RADIUS) {
      const force = (1 - dist / REPULSION_RADIUS) * REPULSION_STRENGTH;
      return Math.sin(Math.atan2(dy, dx)) * force;
    }
    return 0;
  });

  const x = useSpring(posX, SPRING_CONFIG);
  const y = useSpring(posY, SPRING_CONFIG);
  const delay = (index * 0.02) % 1.5;

  return (
    <motion.div
      animate={{ opacity: [dot.opacity * 0.6, dot.opacity, dot.opacity * 0.6] }}
      className="absolute rounded-full will-change-transform"
      initial={{ opacity: dot.opacity * 0.6 }}
      style={{
        width: DOT_SIZE,
        height: DOT_SIZE,
        left: dot.baseX,
        top: dot.baseY,
        x,
        y,
        background: "rgba(30, 61, 74, 0.55)",
      }}
      transition={{
        opacity: {
          duration: 2 + (index % 4) * 0.3,
          repeat: Infinity,
          ease: [0.4, 0, 0.2, 1],
          delay,
          times: [0, 0.5, 1],
        },
      }}
    />
  );
}

export default function HeroDotBg() {
  const containerRef = useRef<HTMLDivElement>(null);
  const mouseX = useMotionValue(Infinity);
  const mouseY = useMotionValue(Infinity);
  const [dots, setDots] = useState<Dot[]>([]);

  useEffect(() => {
    const update = () => {
      if (!containerRef.current) return;
      const { width, height } = containerRef.current.getBoundingClientRect();
      setDots(generateDots(width, height));
    };
    update();
    const ro = new ResizeObserver(update);
    if (containerRef.current) ro.observe(containerRef.current);
    return () => ro.disconnect();
  }, []);

  const handleMouseMove = (e: React.MouseEvent<HTMLDivElement>) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    mouseX.set(e.clientX - rect.left);
    mouseY.set(e.clientY - rect.top);
  };

  return (
    <div
      ref={containerRef}
      className="absolute inset-0 overflow-hidden pointer-events-none"
      onMouseMove={handleMouseMove}
      onMouseLeave={() => { mouseX.set(Infinity); mouseY.set(Infinity); }}
      style={{ pointerEvents: "all" }}
    >
      {dots.map((dot, i) => (
        <DotItem key={dot.id} dot={dot} index={i} mouseX={mouseX} mouseY={mouseY} />
      ))}
    </div>
  );
}
