"use client";

import { ArrowRight } from "lucide-react";
import { useState } from "react";
import { cn } from "@/lib/utils";

export interface PlaylistFlipCardProps {
  title: string;
  description: string;
  badge: string;
  gradient: string;
  url: string;
  icon: React.ReactNode;
}

export default function PlaylistFlipCard({
  title,
  description,
  badge,
  gradient,
  url,
  icon,
}: PlaylistFlipCardProps) {
  const [isFlipped, setIsFlipped] = useState(false);

  return (
    <div
      className="group relative h-[280px] w-full [perspective:2000px]"
      onMouseEnter={() => setIsFlipped(true)}
      onMouseLeave={() => setIsFlipped(false)}
    >
      <div
        className={cn(
          "relative h-full w-full [transform-style:preserve-3d] transition-all duration-700",
          isFlipped ? "[transform:rotateY(180deg)]" : "[transform:rotateY(0deg)]"
        )}
      >
        {/* Front */}
        <div
          className={cn(
            "absolute inset-0 h-full w-full [backface-visibility:hidden] [transform:rotateY(0deg)]",
            "overflow-hidden rounded-2xl border border-white/10",
            "flex flex-col",
            "transition-all duration-700",
            isFlipped ? "opacity-0" : "opacity-100"
          )}
          style={{ background: "rgba(255,255,255,0.06)" }}
        >
          {/* Gradient banner */}
          <div
            className="flex items-center justify-between px-5 py-5"
            style={{ background: gradient, height: "100px" }}
          >
            <span className="text-white/90">{icon}</span>
            <span
              className="text-[10px] font-bold uppercase tracking-widest border border-white/25 rounded-full px-3 py-1"
              style={{ background: "rgba(0,0,0,0.2)", color: "rgba(255,255,255,0.9)" }}
            >
              {badge}
            </span>
          </div>

          {/* Title area */}
          <div className="flex flex-1 flex-col justify-between p-5">
            <p
              className="font-semibold text-[0.9rem] leading-snug transition-all duration-500 ease-out group-hover:translate-y-[-3px]"
              style={{ color: "var(--white)" }}
            >
              {title}
            </p>
            <div className="flex items-center gap-1.5 mt-3" style={{ color: "rgba(255,255,255,0.38)" }}>
              <span className="text-[0.7rem] font-medium uppercase tracking-wider">Hover to explore</span>
              <ArrowRight className="h-3 w-3" />
            </div>
          </div>
        </div>

        {/* Back */}
        <a
          href={url}
          target="_blank"
          rel="noopener noreferrer"
          className={cn(
            "absolute inset-0 h-full w-full [backface-visibility:hidden] [transform:rotateY(180deg)]",
            "rounded-2xl p-5 flex flex-col border border-white/10",
            "transition-all duration-700 no-underline",
            isFlipped ? "opacity-100" : "opacity-0"
          )}
          style={{ background: "rgba(255,255,255,0.08)" }}
          onClick={(e) => { if (!isFlipped) e.preventDefault(); }}
        >
          {/* Gradient top bar */}
          <div
            className="h-1 w-full rounded-full mb-4 flex-shrink-0"
            style={{ background: gradient }}
          />

          <div className="flex-1 flex flex-col gap-3">
            <p
              className="font-semibold text-[0.9rem] leading-snug transition-all duration-500 group-hover:translate-y-[-2px]"
              style={{ color: "var(--white)" }}
            >
              {title}
            </p>
            <p
              className="text-[0.78rem] leading-relaxed"
              style={{
                color: "rgba(255,255,255,0.52)",
                transitionDelay: "100ms",
                transform: isFlipped ? "translateX(0)" : "translateX(-8px)",
                opacity: isFlipped ? 1 : 0,
                transition: "transform 0.5s ease, opacity 0.5s ease",
              }}
            >
              {description}
            </p>
          </div>

          {/* CTA */}
          <div
            className={cn(
              "group/cta mt-4 -mx-2 flex items-center justify-between rounded-xl px-3 py-2.5",
              "transition-all duration-300",
              "hover:scale-[1.02]"
            )}
            style={{ background: "rgba(255,255,255,0.07)", border: "1px solid rgba(255,255,255,0.1)" }}
          >
            <span
              className="font-semibold text-[0.82rem] transition-colors duration-300"
              style={{ color: "var(--white)", fontFamily: "'Poppins', sans-serif" }}
            >
              Watch Playlist
            </span>
            <ArrowRight
              className="h-4 w-4 transition-all duration-300 group-hover/cta:translate-x-0.5"
              style={{ color: "rgba(255,255,255,0.7)" }}
            />
          </div>
        </a>
      </div>
    </div>
  );
}
